/**
 * NormalizeExpressionText helper.
 *
 * @param sourceCode - Current source code instance.
 * @param expression - Value to inspect.
 *
 * @returns NormalizeExpressionText helper result.
 */
const normalizeExpressionText = (
    sourceCode: Readonly<TSESLint.SourceCode>,
    expression: Readonly<TSESTree.Expression>
): string => {
    let normalizedExpressionText = sourceCode.getText(expression).trim();

    while (
        normalizedExpressionText.startsWith("(") &&
        normalizedExpressionText.endsWith(")")
    ) {
        normalizedExpressionText = normalizedExpressionText.slice(1, -1).trim();
    }

    return normalizedExpressionText;
};

